function findIndex(arr: number[], target: number): number | -1 {
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] === target) return i;
  }
  return -1;
}

const idx: number = findIndex([10, 20, 30], 20);
console.log(idx);  // 1

